{"cmd":"cd /mnt/workspace/jkh/Search-R1 && python - <<'PY'
import json
from pathlib import Path
p=Path('data/nq_search/soft_cold.jsonl')
f=Path('data/nq_search/soft_cold_failed.jsonl')
for path in [p,f]:
    n=0
    ids=set()
    s2=0
    if path.exists():
        with path.open('r',encoding='utf-8',errors='ignore') as fh:
            for line in fh:
                line=line.strip()
                if not line:
                    continue
                try:
                    obj=json.loads(line)
                except Exception:
                    continue
                n+=1
                rid=str(obj.get('id',''))
                if rid:
                    ids.add(rid)
                try:
                    if int(obj.get('search_turns',0))>1:
                        s2+=1
                except Exception:
                    pass
    print(path, 'rows', n, 'unique_ids', len(ids), 'search_gt1', s2)
PY","max_output_tokens":12000}

