{"cmd":"cd /mnt/workspace/jkh/Search-R1 && python - <<'PY'
import json
from pathlib import Path
from collections import Counter

succ=Path('data/nq_search/soft_cold.jsonl')
fail=Path('data/nq_search/soft_cold_failed.jsonl')

def load(path):
    rows=[]
    if path.exists():
        with path.open('r',encoding='utf-8',errors='ignore') as f:
            for ln in f:
                ln=ln.strip()
                if not ln:
                    continue
                try:
                    rows.append(json.loads(ln))
                except Exception:
                    pass
    return rows

s=load(succ)
f=load(fail)
ids_s={str(r.get('id','')) for r in s if r.get('id') is not None}
ids_f={str(r.get('id','')) for r in f if r.get('id') is not None}
print('succ_rows',len(s),'succ_ids',len(ids_s))
print('fail_rows',len(f),'fail_ids',len(ids_f))
print('covered_ids_union',len(ids_s|ids_f))

c=Counter()
search_turns=Counter()
for r in s:
    c['succ_total']+=1
    search_turns[int(r.get('search_turns',0) or 0)] +=1
print('succ search_turns top',search_turns.most_common(6))
print('succ search_turns>1',sum(v for k,v in search_turns.items() if k>1))

fr=Counter()
for r in f:
    fr[str(r.get('final_failure_reason',''))[:120]] += 1
print('top fail reasons:')
for k,v in fr.most_common(8):
    print(v,k)
PY"}

